package com.tidex.mobile.meshimport android.content.Contextimport android.net.ConnectivityManagerimport android.net.Networkimport android.net.NetworkCapabilitiesimport android.net.NetworkRequestclass NetworkMonitor(private val context: Context) {    private val connectivityManager = context.getSystemService(Context.CONNECTIVITY_SERVICE) as ConnectivityManager    private var callback: ConnectivityManager.NetworkCallback? = null    fun isInternetAvailable(): Boolean {        val active = connectivityManager.activeNetwork ?: return false        val caps = connectivityManager.getNetworkCapabilities(active) ?: return false        return caps.hasCapability(NetworkCapabilities.NET_CAPABILITY_INTERNET) &&            caps.hasCapability(NetworkCapabilities.NET_CAPABILITY_VALIDATED)    }    fun start(onInternetRestored: () -> Unit) {        if (callback != null) return        callback = object : ConnectivityManager.NetworkCallback() {            override fun onAvailable(network: Network) {                if (isInternetAvailable()) {                    onInternetRestored()                }            }        }        connectivityManager.registerNetworkCallback(            NetworkRequest.Builder()                .addCapability(NetworkCapabilities.NET_CAPABILITY_INTERNET)                .build(),            callback!!        )    }    fun stop() {        callback?.let { connectivityManager.unregisterNetworkCallback(it) }        callback = null    }}